#!/usr/bin/env bun
/**
 * Scans for named imports from auto-generated stub files and adds the missing exports.
 */

import { execSync } from 'child_process';
import { existsSync, readFileSync, writeFileSync } from 'fs';
import { dirname, resolve } from 'path';

const ROOT = resolve(import.meta.dir, '..');
const STUB_MARKER = 'Auto-generated by scripts/generate-stubs.ts';

// Run bun build to find errors
console.log('Running bun build to find missing exports...');
let output: string;
try {
  output = execSync(
    `bun build src/entrypoints/cli.tsx --outdir=dist --target=bun ` +
    `--define 'MACRO.VERSION="0.0.0-snapshot"' ` +
    `--define 'MACRO.BUILD_TIME="2026-03-31"' ` +
    `--define 'MACRO.PACKAGE_URL="claude-code-snapshot"' ` +
    `--define 'MACRO.NATIVE_PACKAGE_URL=""' ` +
    `--define 'MACRO.FEEDBACK_CHANNEL=""' ` +
    `--define 'MACRO.ISSUES_EXPLAINER=""' ` +
    `--define 'MACRO.VERSION_CHANGELOG=""'`,
    { cwd: ROOT, encoding: 'utf-8', maxBuffer: 10 * 1024 * 1024 }
  );
} catch (e: any) {
  output = (e.stderr || '') + (e.stdout || '');
}

// Parse "No matching export" errors
const exportErrorRegex = /error: No matching export in "([^"]+)" for import "([^"]+)"/g;
const fixes = new Map<string, Set<string>>(); // file -> set of export names

let match: RegExpExecArray | null;
while ((match = exportErrorRegex.exec(output)) !== null) {
  const [, filePath, exportName] = match;
  const absPath = resolve(ROOT, filePath);
  if (!fixes.has(absPath)) {
    fixes.set(absPath, new Set());
  }
  fixes.get(absPath)!.add(exportName);
}

console.log(`Found ${fixes.size} files needing export fixes\n`);

for (const [filePath, exports] of fixes) {
  if (!existsSync(filePath)) {
    console.log(`  SKIP (not found): ${filePath}`);
    continue;
  }

  const content = readFileSync(filePath, 'utf-8');
  const exportNames = [...exports];

  // Check which exports are already present
  const missing = exportNames.filter(name => {
    const regex = new RegExp(`export\\s+(?:const|let|var|function|class)\\s+${name}\\b`);
    return !regex.test(content);
  });

  if (missing.length === 0) continue;

  // Add missing exports
  const additions = missing.map(name => `export const ${name}: any = {};`).join('\n');
  const newContent = content.trimEnd() + '\n' + additions + '\n';

  writeFileSync(filePath, newContent);
  const relPath = filePath.replace(ROOT + '/', '');
  console.log(`  Fixed: ${relPath} — added: ${missing.join(', ')}`);
}

console.log('\nDone!');
